changeSet.sql:
-- Backfill stubs from chunks_384 INSERT INTO nexus.catalog_collections (tenant_id, name) SELECT DISTINCT tenant_id, collection FROM nexus.chunks_384 ON CONFLICT (tenant_id, name) DO NOTHING;
-- Backfill stubs from chunks_768 INSERT INTO nexus.catalog_collections (tenant_id, name) SELECT DISTINCT tenant_id, collection FROM nexus.chunks_768 ON CONFLICT (tenant_id, name) DO NOTHING;
-- Backfill stubs from chunks_1024 INSERT INTO nexus.catalog_collections (tenant_id, name) SELECT DISTINCT tenant_id, collection FROM nexus.chunks_1024 ON CONFLICT (tenant_id, name) DO NOTHING;
-- Backfill stubs from chash_index INSERT INTO nexus.catalog_collections (tenant_id, name) SELECT DISTINCT tenant_id, physical_collection FROM nexus.chash_index ON CONFLICT (tenant_id, name) DO NOTHING;
-- Backfill stubs from topic_assignments (non-null, non-empty source_collection only) INSERT INTO nexus.catalog_collections (tenant_id, name) SELECT DISTINCT tenant_id, source_collection FROM nexus.topic_assignments WHERE source_collection IS NOT NULL AND source_collection != '' ON CONFLICT (tenant_id, name) DO NOTHING;
